class AppError(Exception):
    pass

class InsufficientFundsError(AppError):
    def __init__(self, account, amount, balance):
        self.account = account
        self.amount = amount
        self.balance = balance
        super().__init__(f'Account {account}: need ${amount}, have ${balance}')

def withdraw(account, amount, balance):
    if amount > balance:
        raise InsufficientFundsError(account, amount, balance)
    return balance - amount

try:
    withdraw('ACC-001', 500, 200)
except InsufficientFundsError as e:
    print(f'Error: {e}')
    print(f'Short by: ${e.amount - e.balance}')
